    subjectId: "science",
    form: "Form 1",
    chapter: "Chapter 1",
    lang: "dlp",
    front: "What does the OXIDISING hazard symbol mean?",
    back: "Chemicals that release oxygen to help other materials burn. Examples: Potassium manganate(VII).",
