export function getSubjectChapters(
  subjectId: string,
  scienceLang?: "bm" | "dlp",
  form: Form | "All" = "Form 1",
): ChapterItem[] {
  if (form === "Form 2" && subjectId === "sejarah") {
    return [
      {
        key: "Chapter 1",
        label: "Chapter 1: Kerajaan Alam Melayu",
        available: true,
        isNew: true,
      },
      {
        key: "Chapter 2",
        label: "Chapter 2: Sistem Pemerintahan dan Kegiatan Ekonomi",
        available: true,
        isNew: true,
      },
      {
        key: "Chapter 3",
        label: "Chapter 3: Sosiobudaya Masyarakat Kerajaan Alam Melayu",
        available: true,
        isNew: true,
      },
      {
        key: "Chapter 4",
        label:
          "Chapter 4: Agama, Kepercayaan dan Keunikan Warisan Masyarakat Kerajaan Alam Melayu",
        available: true,
        subtopics: [
          "4.1 Agama dan Kepercayaan",
          "4.2 Keunikan Warisan Masyarakat Kerajaan Alam Melayu",
        ],
      },
      {
        key: "Chapter 5",
        label: "Chapter 5: Kesultanan Melayu Melaka",
        available: true,
        selectable: true,
        subtopics: [
          "5.1 Pengasasan Kesultanan Melayu Melaka",
          "5.2 Kegemilangan Kesultanan Melayu Melaka",
          "5.3 Pengakhiran Kesultanan Melayu Melaka yang Berpusat di Melaka",
        ],
      },
      {
        key: "Chapter 6",
        label: "Chapter 6: Kesultanan Johor Riau",
        available: false,
        selectable: true,
        subtopics: [
          "6.1 Pengasasan Kesultanan Johor Riau",
          "6.2 Kegemilangan Kesultanan Johor Riau",
        ],
      },
      {
        key: "Chapter 7",
        label: "Chapter 7: Kesultanan Melayu Pahang, Perak, Terengganu dan Selangor",
        available: true,
        selectable: true,
        subtopics: [
          "7.1 Pengasasan Kesultanan Pahang, Perak, Terengganu dan Selangor",
          "7.2 Warisan Kesultanan Melayu Melaka di Pahang, Perak, Terengganu dan Selangor",
        ],
      },
      {
        key: "Chapter 8",
        label: "Chapter 8: Kerajaan Kedah, Kelantan, Negeri Sembilan dan Perlis",
        available: true,
        selectable: true,
        subtopics: [
          "8.1 Pengasasan Kerajaan Kedah, Kelantan, Negeri Sembilan dan Perlis",
          "8.2 Hubungan Kerajaan Kedah, Kelantan, Negeri Sembilan dan Perlis dengan Negeri-negeri Melayu yang Lain",
        ],
      },
      {
        key: "Chapter 9",
        label: "Chapter 9: Warisan Kerajaan Kedah, Kelantan, Negeri Sembilan dan Perlis",
        available: true,
        selectable: true,
        subtopics: [
          "9.1 Warisan Kerajaan Kedah, Kelantan dan Perlis",
          "9.2 Keunikan Adat dan Pemerintahan Negeri Sembilan",
        ],
      },
      {
        key: "Chapter 10",
        label: "Chapter 10: Sarawak dan Sabah",
        available: true,
        selectable: true,
        subtopics: [
          "10.1 Sarawak dan Sabah dalam Alam Melayu",
          "10.2 Kemunculan Pemerintahan Tempatan",
          "10.3 Kegiatan Ekonomi Masyarakat Sarawak dan Sabah",
          "10.4 Keunikan Masyarakat Bumiputera Sarawak dan Sabah",
        ],
      },
    ];
  }

  if (form === "Form 2" && subjectId === "geography") {
    return [
      { key: "Chapter 1", label: "Chapter 1: Skala dan Jarak", available: true },
      { key: "Chapter 2", label: "Chapter 2: Peta Topografi", available: true },
      {
        key: "Chapter 3",
        label: "Chapter 3: Pengaruh Pergerakan Bumi terhadap Cuaca dan Iklim",
        available: true,
      },
      { key: "Chapter 4", label: "Chapter 4: Cuaca dan Iklim di Malaysia", available: true },
      { key: "Chapter 5", label: "Chapter 5: Pengangkutan di Malaysia", available: true },
      { key: "Chapter 6", label: "Chapter 6: Telekomunikasi di Malaysia", available: true },
      {
        key: "Chapter 7",
        label: "Chapter 7: Kepelbagaian Iklim dan Pengaruhnya terhadap Kegiatan Manusia di Asia",
        available: true,
      },
      {
        key: "Chapter 8",
        label: "Chapter 8: Jenis dan Kemajuan Pengangkutan di Asia",
        available: true,
      },
      { key: "Chapter 9", label: "Chapter 9: Pemanasan Global", available: true },
      { key: "Chapter 10", label: "Chapter 10: Teknologi Hijau", available: true },
    ];
  }

  if (form === "Form 2" && subjectId === "science" && scienceLang) {
    const titles: Array<{ bm: string; dlp: string }> = [
      { bm: "Biodiversiti", dlp: "Biodiversity" },
      { bm: "Ekosistem", dlp: "Ecosystem" },
      { bm: "Nutrisi", dlp: "Nutrition" },
      { bm: "Kesihatan Manusia", dlp: "Human Health" },
      { bm: "Air dan Larutan", dlp: "Water and Solution" },
      { bm: "Asid dan Alkali", dlp: "Acids and Alkalis" },
      { bm: "Keelektrikan dan Kemagnetan", dlp: "Electricity and Magnetism" },
      { bm: "Daya dan Gerakan", dlp: "Force and Motion" },
      { bm: "Haba", dlp: "Heat" },
      { bm: "Gelombang Bunyi", dlp: "Sound Waves" },
      { bm: "Bintang dan Galaksi dalam Alam Semesta", dlp: "Stars and Galaxies in the Universe" },
      { bm: "Sistem Suria", dlp: "Solar System" },
      { bm: "Meteoroid, Asteroid, Komet", dlp: "Meteoroids, Asteroids, Comets" },
    ];
    const prefix = scienceLang === "bm" ? "Bab" : "Chapter";
    return titles.map((t, i) => {
      const n = i + 1;
      return {
        key: `Chapter ${n}`,
        label: `${prefix} ${n}: ${scienceLang === "bm" ? t.bm : t.dlp}`,
        available: true,
      };
    });
  }

  if (form !== "Form 1" && form !== "All") return [];

  if (subjectId === "sejarah") {
    return sejarahForm1Chapters.map((c) => ({
      key: `Chapter ${c.num}`,
      label: `Chapter ${c.num}: ${c.title}`,
      available: c.available,
      isNew: c.isNew,
    }));
  }
  if (subjectId === "english") {
    return englishCategories.map((c) => ({
      key: `Chapter ${c.id}`,
      label: c.name,
      available: true,
      isNew: false,
    }));
  }
  if (subjectId === "science" && scienceLang) {
    const prefix = scienceLang === "bm" ? "Bab" : "Chapter";
    return scienceForm1ChaptersBilingual.map((c) => ({
      key: `Chapter ${c.num}`,
      label: `${prefix} ${c.num}: ${scienceLang === "bm" ? c.bm : c.dlp}`,
      available: true,
      isNew: c.num === 1,
    }));
  }
  if (subjectId === "math" && scienceLang) {
    const prefix = scienceLang === "bm" ? "Bab" : "Chapter";
    return mathForm1ChaptersBilingual.map((c) => ({
      key: `Chapter ${c.num}`,
      label: `${prefix} ${c.num}: ${scienceLang === "bm" ? c.bm : c.dlp}`,
      available: true,
      isNew: c.num === 1,
    }));
  }

  return otherSubjectChapters[subjectId] ?? [];
}
export function getItemChapterKey(item: {
  id: string;
  subjectId: string;
  chapter?: string;
}): string | null {
  if (item.subjectId === "sejarah") {
    const n = sejarahChapterFromId(item.id);
    return n ? `Chapter ${n}` : null;
  }
  if (item.subjectId === "geography") {
    const n = geographyChapterFromId(item.id);
    return n ? `Chapter ${n}` : null;
  }
  return item.chapter ?? null;
}
